SELECT job_title
FROM job_postings
WHERE rating > (SELECT AVG(rating) FROM job_postings);

SELECT job_title, average_salary
FROM salary_benchmarks
WHERE average_salary > 50000;

SELECT job_id, job_title, salary
FROM job_postings
WHERE state = 'NY' AND salary > (SELECT AVG(salary) FROM job_postings);

SELECT DISTINCT city, job_title 
FROM job_postings
ORDER BY city, job_title;

SELECT j.*
FROM job_postings j
WHERE j.salary = (
  SELECT MIN(salary)
  FROM job_postings
);

SELECT job_title, city, salary
FROM job_postings
WHERE city = 'Desired City';
